import{e as a,a1 as e,o as t,s as o}from"./chunks/framework.B6jTn2VX.js";const h=JSON.parse('{"title":"Migration from v0","description":"","frontmatter":{"pageClass":"migration-page"},"headers":[],"relativePath":"docs/migration.md","filePath":"docs/migration.md","lastUpdated":1780355057000}'),n={name:"docs/migration.md"};function c(p,s,d,l,i,r){return e(),t("div",null,[...s[0]||(s[0]=[o(`<h1 id="migration-from-v0" tabindex="-1">Migration from v0 <a class="header-anchor" href="#migration-from-v0" aria-label="Permalink to “Migration from v0”">​</a></h1><p>A guide for moving an existing app onto <code>frappe-ui</code> v1. Work through one component family at a time. Each section opens with a before/after table. For the full change list see the <a href="https://github.com/frappe/frappe-ui/blob/main/v1-release/changelog.md" target="_blank" rel="noreferrer">changelog</a>; for the rationale behind each API see the <a href="https://github.com/frappe/frappe-ui/tree/main/v1-release" target="_blank" rel="noreferrer">v1 release specs</a>.</p><p>After each pass, <code>grep</code> for the old prop or slot name to catch anything missed, then test the flows you touched. Type-checking won&#39;t catch focus, slot renames, or visual regressions.</p><h2 id="dialog" tabindex="-1">Dialog <a class="header-anchor" href="#dialog" aria-label="Permalink to “Dialog”">​</a></h2><p>The <code>options</code> blob is flattened into top-level props. See the <a href="./components/dialog">Dialog</a> component page for the full API.</p><table tabindex="0"><thead><tr><th>Before</th><th>After</th></tr></thead><tbody><tr><td><code>v-model=&quot;show&quot;</code></td><td><code>v-model:open=&quot;show&quot;</code></td></tr><tr><td><code>:options=&quot;{ title, size, actions }&quot;</code></td><td><code>title</code> / <code>size</code> / <code>:actions</code></td></tr><tr><td><code>disableOutsideClickToClose</code></td><td><code>:dismissible=&quot;false&quot;</code></td></tr><tr><td><code>&lt;template #body-content&gt;</code></td><td>default slot</td></tr><tr><td><code>&lt;template #body-title&gt;</code></td><td><code>&lt;template #title&gt;</code></td></tr><tr><td><code>&lt;template #body&gt;</code></td><td><code>bare</code> prop + default slot</td></tr><tr><td><code>onClick: (close) =&gt; …</code></td><td><code>onClick: ({ close }) =&gt; …</code></td></tr><tr><td>manual focus hacks / <code>v-focus</code></td><td><code>autofocus</code> attr on a descendant</td></tr></tbody></table><div class="language-vue"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_1th9sy">&lt;!-- Before --&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">Dialog</span><span class="s_1jjt6x"> :</span><span class="s_1i4ay4">options</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_13ahmt">{</span><span class="s_r4oegk"> title</span><span class="s_1jjt6x">: </span><span class="s_w1p9wo">&#39;</span><span class="s_2575z4">Edit Item</span><span class="s_w1p9wo">&#39;</span><span class="s_13ahmt"> }</span><span class="s_w1p9wo">&quot;</span><span class="s_1i4ay4"> v-model</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_22m8k2">show</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_6am9cx">  &lt;template #body-content&gt;</span></span>
<span class="line"><span class="s_6am9cx">    &lt;FormControl label=&quot;Name&quot; v-model=&quot;item.name&quot; /&gt;</span></span>
<span class="line"><span class="s_6am9cx">  &lt;/template&gt;</span></span>
<span class="line"><span class="s_6am9cx">  &lt;template #actions&gt;</span></span>
<span class="line"><span class="s_6am9cx">    &lt;Button variant=&quot;solid&quot; @click=&quot;save&quot;&gt;Save&lt;/Button&gt;</span></span>
<span class="line"><span class="s_6am9cx">  &lt;/template&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">Dialog</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">&lt;!-- After --&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">Dialog</span><span class="s_1i4ay4"> title</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">Edit Item</span><span class="s_w1p9wo">&quot;</span><span class="s_1i4ay4"> v-model</span><span class="s_1jjt6x">:</span><span class="s_1i4ay4">open</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_22m8k2">show</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_6am9cx">  &lt;FormControl label=&quot;Name&quot; v-model=&quot;item.name&quot; /&gt;</span></span>
<span class="line"><span class="s_6am9cx">  &lt;template #actions&gt;</span></span>
<span class="line"><span class="s_6am9cx">    &lt;Button variant=&quot;solid&quot; @click=&quot;save&quot;&gt;Save&lt;/Button&gt;</span></span>
<span class="line"><span class="s_6am9cx">  &lt;/template&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">Dialog</span><span class="s_1zd9e2">&gt;</span></span></code></pre></div><p>For reactive <code>:options</code> objects, spread them: <code>&lt;Dialog v-bind=&quot;opts || {}&quot; /&gt;</code>. For the imperative API, use <code>dialog.confirm</code> / <code>dialog.danger</code> / <code>dialog.prompt</code> from <code>frappe-ui</code> (callback-based: <code>onConfirm</code> resolves to close, throws to stay open) and wrap your app root in <code>&lt;FrappeUIProvider&gt;</code>.</p><h2 id="datepicker-timepicker-family" tabindex="-1">DatePicker / TimePicker family <a class="header-anchor" href="#datepicker-timepicker-family" aria-label="Permalink to “DatePicker / TimePicker family”">​</a></h2><p>Covers <code>DatePicker</code>, <code>DateRangePicker</code>, <code>DateTimePicker</code>, and <code>TimePicker</code>. They share the popover-trigger vocabulary.</p><table tabindex="0"><thead><tr><th>Before</th><th>After</th></tr></thead><tbody><tr><td><code>:value</code> prop</td><td><code>v-model</code></td></tr><tr><td><code>@change</code></td><td><code>@update:modelValue</code></td></tr><tr><td><code>placement=&quot;bottom-start&quot;</code></td><td><code>side</code> + <code>align</code> + <code>offset</code></td></tr><tr><td><code>:autoClose</code></td><td><code>:keepOpen</code> (inverted)</td></tr><tr><td><code>allowCustom</code> / <code>readonly</code></td><td><code>typeable</code></td></tr><tr><td><code>minDate</code>/<code>maxDate</code>/<code>minTime</code>/<code>maxTime</code></td><td><code>min</code> / <code>max</code></td></tr><tr><td><code>#target</code></td><td><code>#trigger</code></td></tr></tbody></table><p>Behavior changes that apply even if you don&#39;t touch your code:</p><ul><li><code>DateRangePicker</code> emits a <code>[from, to]</code> tuple. Update handlers that called <code>.split(&#39;,&#39;)</code> on the value.</li><li><code>DateTimePicker</code> no longer auto-closes on date click. Close from <code>@update:modelValue</code> or add an <code>#actions</code> Apply button.</li><li>The popover footer and auto Clear button were removed. Render an explicit Clear inside <code>#actions</code> if you relied on it.</li><li><code>DateRangePicker.clearable</code> now defaults to <code>true</code>. Pass <code>:clearable=&quot;false&quot;</code> to opt out.</li></ul><h2 id="selection-family-dropdown-select-combobox-multiselect" tabindex="-1">Selection family (Dropdown / Select / Combobox / MultiSelect) <a class="header-anchor" href="#selection-family-dropdown-select-combobox-multiselect" aria-label="Permalink to “Selection family (Dropdown / Select / Combobox / MultiSelect)”">​</a></h2><table tabindex="0"><thead><tr><th>Before</th><th>After</th></tr></thead><tbody><tr><td>Dropdown <code>{ group, items }</code></td><td><code>{ group, options }</code></td></tr><tr><td>Select <code>#item-*</code> slot prop <code>option</code></td><td>slot prop <code>item</code></td></tr><tr><td>chevron / trailing content</td><td><code>#suffix</code> slot (replaces chevron)</td></tr><tr><td>Combobox <code>createOption</code></td><td><code>type: &#39;custom&#39;</code> option + <code>condition</code></td></tr></tbody></table><p>For the deprecated <code>Autocomplete</code>, see <a href="#autocomplete-deprecated">Autocomplete (deprecated)</a>.</p><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to “Inputs”">​</a></h2><p>Covers <code>TextInput</code>, <code>Textarea</code>, <code>Password</code>, <code>Checkbox</code>, <code>Switch</code>, <code>Rating</code>, <code>Slider</code>. All share the labeling contract (<code>label</code> / <code>description</code> / <code>error</code> / <code>required</code>).</p><table tabindex="0"><thead><tr><th>Before</th><th>After</th></tr></thead><tbody><tr><td><code>Rating</code> <code>:rating_from</code></td><td><code>:max</code></td></tr><tr><td><code>Rating</code> <code>:readonly</code></td><td><code>:disabled</code></td></tr><tr><td><code>Switch</code> <code>@change</code></td><td><code>@update:modelValue</code></td></tr><tr><td><code>Switch.labelClasses</code> / <code>Checkbox.padding</code></td><td><code>data-*</code> styling hooks</td></tr><tr><td><code>Password</code> <code>:value</code> + <code>@input</code> workaround</td><td><code>v-model</code> (now works)</td></tr></tbody></table><p><code>Slider</code> no longer hardcodes <code>aria-label=&quot;Volume&quot;</code>. Pass <code>label</code> explicitly so the control is announced correctly.</p><p>The legacy <code>Input</code> component is deprecated. Use <a href="./components/textinput"><code>TextInput</code></a> for text-like modes, or <code>Textarea</code> / <code>Select</code> / <code>Checkbox</code> for the other type modes it accepted.</p><h2 id="divider" tabindex="-1">Divider <a class="header-anchor" href="#divider" aria-label="Permalink to “Divider”">​</a></h2><table tabindex="0"><thead><tr><th>Before</th><th>After</th></tr></thead><tbody><tr><td><code>action.handler</code></td><td><code>action.onClick</code></td></tr></tbody></table><h2 id="icons" tabindex="-1">Icons <a class="header-anchor" href="#icons" aria-label="Permalink to “Icons”">​</a></h2><p>Replace <code>FeatherIcon</code> and Feather-name strings with <code>lucide-*</code> strings or a <code>Component</code>:</p><div class="language-vue"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_1th9sy">&lt;!-- Before --&gt;</span><span class="s_1zd9e2">        &lt;</span><span class="s_1uuh8p">Button</span><span class="s_1i4ay4"> icon</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">plus</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2"> /&gt;</span></span>
<span class="line"><span class="s_1th9sy">&lt;!-- After --&gt;</span><span class="s_1zd9e2">         &lt;</span><span class="s_1uuh8p">Button</span><span class="s_1i4ay4"> icon</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">lucide-plus</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2"> /&gt;</span></span></code></pre></div><p>Same for icon-name strings in <code>Dropdown</code> options:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_1th9sy">// Before</span></span>
<span class="line"><span class="s_252irl">const</span><span class="s_295sjd"> options</span><span class="s_2ekfrt"> =</span><span class="s_13ahmt"> [{</span><span class="s_r4oegk"> label</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">Edit</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span><span class="s_r4oegk"> icon</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">edit</span><span class="s_w1p9wo">&#39;</span><span class="s_13ahmt"> }]</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">// After</span></span>
<span class="line"><span class="s_252irl">const</span><span class="s_295sjd"> options</span><span class="s_2ekfrt"> =</span><span class="s_13ahmt"> [{</span><span class="s_r4oegk"> label</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">Edit</span><span class="s_w1p9wo">&#39;</span><span class="s_1jjt6x">,</span><span class="s_r4oegk"> icon</span><span class="s_1jjt6x">:</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">lucide-pen</span><span class="s_w1p9wo">&#39;</span><span class="s_13ahmt"> }]</span></span></code></pre></div><h2 id="editor" tabindex="-1">Editor <a class="header-anchor" href="#editor" aria-label="Permalink to “Editor”">​</a></h2><p>The v0 monolith <code>&lt;TextEditor&gt;</code> (imported from <code>frappe-ui</code>) is replaced by the <code>frappe-ui/editor</code> family: a headless <code>&lt;Editor&gt;</code> you compose with <strong>kits</strong> (bundled, configurable extension sets) and <strong>building-block</strong> menus. Everything moves to the <code>frappe-ui/editor</code> subpath; nothing editor-related is exported from top-level <code>frappe-ui</code> except the deprecated v0 alias, so the two coexist during the migration window. See the <a href="./molecules/editor">Editor</a> page for the full API and recipes.</p><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_1th9sy">// Before</span></span>
<span class="line"><span class="s_edvzsf">import</span><span class="s_13ahmt"> { </span><span class="s_4q1z3w">TextEditor</span><span class="s_1jjt6x">,</span><span class="s_4q1z3w"> TextEditorFixedMenu</span><span class="s_13ahmt"> }</span><span class="s_edvzsf"> from</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">frappe-ui</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"><span class="s_1th9sy">// After</span></span>
<span class="line"><span class="s_edvzsf">import</span><span class="s_13ahmt"> { </span><span class="s_4q1z3w">Editor</span><span class="s_1jjt6x">,</span><span class="s_4q1z3w"> EditorFixedMenu</span><span class="s_1jjt6x">,</span><span class="s_4q1z3w"> RichTextKit</span><span class="s_1jjt6x">,</span><span class="s_4q1z3w"> articleToolbar</span><span class="s_13ahmt"> }</span><span class="s_edvzsf"> from</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">frappe-ui/editor</span><span class="s_w1p9wo">&#39;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Before</th><th>After</th></tr></thead><tbody><tr><td><code>import … from &#39;frappe-ui&#39;</code></td><td><code>import … from &#39;frappe-ui/editor&#39;</code></td></tr><tr><td><code>&lt;TextEditor&gt;</code></td><td><code>&lt;Editor&gt;</code></td></tr><tr><td><code>:content=&quot;x&quot; @change=&quot;x = $event&quot;</code></td><td><code>v-model=&quot;x&quot;</code> (<code>@change</code> still emitted)</td></tr><tr><td>HTML string only</td><td><code>v-model</code> + <code>format=&quot;json&quot;</code> for a JSON value</td></tr><tr><td><code>:starterkit-options=&quot;{ heading: { levels } }&quot;</code></td><td><code>RichTextKit.configure({ heading: { levels } })</code> in <code>:extensions</code></td></tr><tr><td>auto-loaded extension set (no opt-out)</td><td>explicit <code>:extensions</code> — pick <code>CommentKit</code> / <code>RichTextKit</code> / <code>InlineKit</code></td></tr><tr><td><code>:mentions</code> / <code>:tags</code> props</td><td><code>kit.configure({ mention: { items, component }, tag: { items } })</code></td></tr><tr><td><code>:bubble-menu=&quot;true&quot;</code></td><td><code>&lt;EditorBubbleMenu :items=&quot;articleToolbar&quot;&gt;</code> in the default slot</td></tr><tr><td><code>:floating-menu=&quot;true&quot;</code></td><td><code>&lt;EditorFloatingMenu :items&gt;</code></td></tr><tr><td><code>&lt;TextEditorFixedMenu :buttons&gt;</code></td><td><code>&lt;EditorFixedMenu :items&gt;</code></td></tr><tr><td><code>&lt;TextEditorContent&gt;</code></td><td><code>&lt;EditorContent&gt;</code></td></tr><tr><td>menu <code>:buttons</code></td><td>menu <code>:items</code></td></tr><tr><td>hand-rolled <code>textEditorMenuButtons</code> array</td><td><code>commentToolbar</code> / <code>articleToolbar</code> / <code>minimalToolbar</code> presets</td></tr><tr><td><code>#top</code> / <code>#bottom</code> / <code>#editor</code> slots</td><td>one default slot — you render <code>EditorContent</code> + menus yourself</td></tr><tr><td><code>:uploadFunction</code> (optional, frappe default)</td><td><code>:upload-function</code> (required to enable uploads)</td></tr></tbody></table><h3 id="compose-don-t-configure" tabindex="-1">Compose, don&#39;t configure <a class="header-anchor" href="#compose-don-t-configure" aria-label="Permalink to “Compose, don&#39;t configure”">​</a></h3><p>v0 took every option as a prop on <code>&lt;TextEditor&gt;</code> and auto-loaded every extension. v1 renders no chrome of its own — you place the building blocks inside its default slot and they pick up the editor from context (the <code>:editor</code> prop is only needed when composing primitives without <code>&lt;Editor&gt;</code>):</p><div class="language-vue"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">script</span><span class="s_1i4ay4"> setup</span><span class="s_1i4ay4"> lang</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">ts</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_edvzsf">import</span><span class="s_13ahmt"> { </span><span class="s_4q1z3w">ref</span><span class="s_13ahmt"> }</span><span class="s_edvzsf"> from</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">vue</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"><span class="s_edvzsf">import</span><span class="s_13ahmt"> { </span><span class="s_4q1z3w">Editor</span><span class="s_1jjt6x">,</span><span class="s_4q1z3w"> EditorContent</span><span class="s_1jjt6x">,</span><span class="s_4q1z3w"> EditorBubbleMenu</span><span class="s_1jjt6x">,</span><span class="s_4q1z3w"> RichTextKit</span><span class="s_1jjt6x">,</span><span class="s_4q1z3w"> articleToolbar</span><span class="s_13ahmt"> }</span><span class="s_edvzsf"> from</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">frappe-ui/editor</span><span class="s_w1p9wo">&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="s_252irl">const</span><span class="s_295sjd"> content</span><span class="s_2ekfrt"> =</span><span class="s_indoxt"> ref</span><span class="s_13ahmt">(</span><span class="s_w1p9wo">&#39;&#39;</span><span class="s_13ahmt">)</span></span>
<span class="line"><span class="s_252irl">const</span><span class="s_295sjd"> extensions</span><span class="s_2ekfrt"> =</span><span class="s_13ahmt"> [</span><span class="s_22m8k2">RichTextKit</span><span class="s_1jjt6x">.</span><span class="s_indoxt">configure</span><span class="s_13ahmt">({</span><span class="s_r4oegk"> heading</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> {</span><span class="s_r4oegk"> levels</span><span class="s_1jjt6x">:</span><span class="s_13ahmt"> [</span><span class="s_40mev6">2</span><span class="s_1jjt6x">,</span><span class="s_40mev6"> 3</span><span class="s_1jjt6x">,</span><span class="s_40mev6"> 4</span><span class="s_1jjt6x">,</span><span class="s_40mev6"> 5</span><span class="s_1jjt6x">,</span><span class="s_40mev6"> 6</span><span class="s_13ahmt">]</span><span class="s_13ahmt"> }</span><span class="s_13ahmt"> })]</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">script</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;</span><span class="s_wac0bt">Editor</span><span class="s_1i4ay4"> v-model</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">content</span><span class="s_w1p9wo">&quot;</span><span class="s_1i4ay4"> :extensions</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">extensions</span><span class="s_w1p9wo">&quot;</span><span class="s_1i4ay4"> placeholder</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">Write…</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">    &lt;</span><span class="s_wac0bt">EditorBubbleMenu</span><span class="s_1i4ay4"> :items</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">articleToolbar</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2"> /&gt;</span></span>
<span class="line"><span class="s_1zd9e2">    &lt;</span><span class="s_wac0bt">EditorContent</span><span class="s_1i4ay4"> class</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_2575z4">prose max-w-none</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2"> /&gt;</span></span>
<span class="line"><span class="s_1zd9e2">  &lt;/</span><span class="s_wac0bt">Editor</span><span class="s_1zd9e2">&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;/</span><span class="s_1uuh8p">template</span><span class="s_1zd9e2">&gt;</span></span></code></pre></div><p>Pick the kit per surface: <code>CommentKit</code> (light — no table/toc/slash), <code>RichTextKit</code> (full document), <code>InlineKit</code> (single-line). Configure kit members in place rather than via props — e.g. mentions/tags through <code>kit.configure({ mention: {...}, tag: {...} })</code>. To keep the mention/tag nodes rendering but disable the live popups, pass <code>mention: { items: null }</code>.</p><p>For a fully custom layout (e.g. a title <code>&lt;textarea&gt;</code> as a sibling of the body), skip <code>&lt;Editor&gt;</code> and drive <code>useEditor</code> yourself — see <a href="./molecules/editor#composing-primitives">Composing primitives</a> — rendering <code>&lt;EditorContent&gt;</code> and the menus as siblings of your own markup.</p><h3 id="gotchas" tabindex="-1">Gotchas <a class="header-anchor" href="#gotchas" aria-label="Permalink to “Gotchas”">​</a></h3><ul><li><strong>Tailwind must scan frappe-ui&#39;s editor source.</strong> Menu icons are literal <code>lucide-*</code> class strings living in <code>frappe-ui/src/molecules/**</code>. Add that glob to your <code>tailwind.config.js</code> <code>content</code>, or the toolbar / bubble / floating icons silently won&#39;t be generated.</li><li><strong>Uploads need an explicit handler.</strong> v0 silently invoked the Frappe upload; v1 requires <code>:upload-function</code>. In a Frappe app: <code>(file) =&gt; useFileUpload().upload(file, {})</code>.</li><li><strong>TipTap must be v3.</strong> The v1 editor is built on TipTap 3 — pin <code>@tiptap/core</code>, <code>@tiptap/pm</code>, and <code>@tiptap/vue-3</code> to <code>^3</code>.</li></ul><h2 id="autocomplete-deprecated" tabindex="-1">Autocomplete (deprecated) <a class="header-anchor" href="#autocomplete-deprecated" aria-label="Permalink to “Autocomplete (deprecated)”">​</a></h2><p><code>Autocomplete</code> still ships (with a one-time dev <code>console.warn</code>) but will be removed in a future major release. It merged single- and multi-select via the <code>multiple</code> boolean; v1 splits them: <a href="./components/combobox"><code>Combobox</code></a> for single, <a href="./components/multiselect"><code>MultiSelect</code></a> for multiple.</p><p>The model value changes shape. <code>Autocomplete</code> took and emitted the full option object; the new components model the value only. <code>Combobox</code> is <code>string | null</code> and <code>MultiSelect</code> is <code>string[]</code>. To read the full option, listen to <code>Combobox</code>&#39;s <code>@update:selected-option</code>.</p><table tabindex="0"><thead><tr><th>Before (<code>Autocomplete</code>)</th><th>After</th></tr></thead><tbody><tr><td><code>:multiple=&quot;false&quot;</code> (default)</td><td>use <code>Combobox</code></td></tr><tr><td><code>:multiple=&quot;true&quot;</code></td><td>use <code>MultiSelect</code></td></tr><tr><td><code>v-model</code> (option or value)</td><td><code>v-model</code> (value / value array)</td></tr><tr><td><code>@change</code></td><td><code>@update:modelValue</code></td></tr><tr><td>grouped <code>{ group, items }</code></td><td>grouped <code>{ group, options }</code></td></tr><tr><td><code>placement</code> (string)</td><td><code>side</code> + <code>align</code></td></tr><tr><td><code>:showFooter</code></td><td><code>#footer</code> slot (MultiSelect has built-in)</td></tr><tr><td><code>:bodyClasses</code></td><td><code>data-slot</code> CSS</td></tr><tr><td><code>:maxOptions</code></td><td>no equivalent</td></tr><tr><td><code>#target</code></td><td><code>#trigger</code></td></tr><tr><td><code>#prefix</code> / <code>#suffix</code> / <code>#item-*</code></td><td>same (<code>#suffix</code> now replaces chevron)</td></tr></tbody></table><div class="language-vue"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_1th9sy">&lt;!-- Before --&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">Autocomplete</span><span class="s_1i4ay4"> v-model</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_22m8k2">country</span><span class="s_w1p9wo">&quot;</span><span class="s_1jjt6x"> :</span><span class="s_1i4ay4">options</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_22m8k2">countries</span><span class="s_w1p9wo">&quot;</span><span class="s_1jjt6x"> @</span><span class="s_1i4ay4">change</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_22m8k2">onChange</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2"> /&gt;</span></span>
<span class="line"><span class="s_1th9sy">&lt;!-- country === { label: &#39;India&#39;, value: &#39;in&#39; } --&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="s_1th9sy">&lt;!-- After --&gt;</span></span>
<span class="line"><span class="s_1zd9e2">&lt;</span><span class="s_1uuh8p">Combobox</span><span class="s_1i4ay4"> v-model</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_22m8k2">country</span><span class="s_w1p9wo">&quot;</span><span class="s_1jjt6x"> :</span><span class="s_1i4ay4">options</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_22m8k2">countries</span><span class="s_w1p9wo">&quot;</span><span class="s_1jjt6x"> @</span><span class="s_1i4ay4">update</span><span class="s_1jjt6x">:</span><span class="s_1i4ay4">model-value</span><span class="s_1jjt6x">=</span><span class="s_w1p9wo">&quot;</span><span class="s_22m8k2">onChange</span><span class="s_w1p9wo">&quot;</span><span class="s_1zd9e2"> /&gt;</span></span>
<span class="line"><span class="s_1th9sy">&lt;!-- country === &#39;in&#39; --&gt;</span></span></code></pre></div><p>Sweep your codebase:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes tokyo-night github-light s_2cy0ei" tabindex="0" dir="ltr"><code><span class="line"><span class="s_euu481">grep</span><span class="s_2d41qv"> -rln</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">&lt;Autocomplete\\b</span><span class="s_w1p9wo">&#39;</span><span class="s_2575z4"> src</span><span class="s_2d41qv"> --include=</span><span class="s_w1p9wo">&#39;</span><span class="s_2575z4">*.vue</span><span class="s_w1p9wo">&#39;</span><span class="s_1th9sy">   # find usages</span></span>
<span class="line"><span class="s_euu481">grep</span><span class="s_2d41qv"> -rln</span><span class="s_w1p9wo"> &#39;</span><span class="s_2575z4">:multiple</span><span class="s_w1p9wo">&#39;</span><span class="s_2575z4"> src</span><span class="s_2d41qv"> --include=</span><span class="s_w1p9wo">&#39;</span><span class="s_2575z4">*.vue</span><span class="s_w1p9wo">&#39;</span><span class="s_1th9sy">         # these become MultiSelect</span></span></code></pre></div><p><code>FormControl</code> itself is not deprecated, but its <code>type=&quot;autocomplete&quot;</code> value is. Switch to <code>type=&quot;combobox&quot;</code>, or use the standalone <a href="./components/combobox"><code>Combobox</code></a>.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to “FAQ”">​</a></h2><p><strong>Will my CSS break?</strong> Where structure changed, components expose <code>data-*</code> hooks (<code>data-slot</code>, <code>data-state</code>, <code>data-size</code>, <code>data-variant</code>). Audit selectors that targeted tags or classes.</p><p><strong>Report bugs:</strong> <a href="https://github.com/frappe/frappe-ui/issues/new" target="_blank" rel="noreferrer">file an issue</a> with the <code>v1-beta</code> label. Include the component name, before/after code, version, and a repro.</p>`,50)])])}const _=a(n,[["render",c]]);export{h as __pageData,_ as default};
